mapper.select:
SELECT id, name, type, price, img, abv, order_count
FROM t_product
WHERE id = #{id}

mapper.update:
UPDATE t_product
SET order_count = order_count + #{quantity}
WHERE id = #{productId}

mapper.select:
SELECT id, name, type, price, img, abv, order_count
FROM t_product
WHERE type = #{type}
  AND name != #{excludeName}
ORDER BY order_count DESC, id ASC
LIMIT #{n}
